#!/usr/bin/env python3
"""
Mtime-based File Cache Utility

Provides a reusable caching mechanism for file-based analyzers that checks
file modification times (mtime) to determine if cached results are still valid.

Usage:
    from development_tools.shared.mtime_cache import MtimeFileCache

    cache = MtimeFileCache(
        project_root=project_root,
        use_cache=True,
        tool_name='my_tool',
        domain='docs'
    )

    # Check if file is cached
    cached_results = cache.get_cached(file_path)
    if cached_results is not None:
        # Use cached results
        return cached_results

    # Process file and cache results
    results = process_file(file_path)
    cache.cache_results(file_path, results)
    cache.save_cache()
"""

from pathlib import Path
from typing import Dict, Generic, Optional, Any, TypeVar, Iterable, Tuple
import hashlib

T = TypeVar("T")  # Generic type for cached results

try:
    from core.logger import get_component_logger

    logger = get_component_logger("development_tools")
except ImportError:
    logger = None

# Cache metadata key for config file mtime
_CONFIG_MTIME_KEY = "__config_mtime__"
_TOOL_HASH_KEY = "__tool_hash__"
_TOOL_MTIMES_KEY = "__tool_mtimes__"
_RUN_STATUS_KEY = "__run_status__"


class MtimeFileCache(Generic[T]):
    """
    Mtime-based file cache for analyzer results.

    Caches results keyed by file path, with validation based on file modification time.
    Only re-processes files that have been modified since the last cache entry.
    """

    def __init__(
        self,
        project_root: Path,
        use_cache: bool = True,
        tool_name: Optional[str] = None,
        domain: Optional[str] = None,
        tool_paths: Optional[Iterable[Path]] = None,
    ):
        """
        Initialize the cache.

        Args:
            project_root: Root directory of the project (for relative path generation)
            use_cache: Whether to use caching (if False, all operations are no-ops)
            tool_name: Name of the tool (e.g., 'analyze_ascii_compliance') - required for standardized storage
            domain: Domain directory (e.g., 'docs') - required for standardized storage
        """
        if tool_name is None or domain is None:
            raise ValueError("tool_name and domain are required for MtimeFileCache")

        self.project_root = project_root.resolve()
        self.use_cache = use_cache
        self.cache_data: Dict[str, Dict[str, Any]] = {}
        self.tool_name = tool_name
        self.domain = domain
        self.use_standardized_storage = True
        self.tool_paths = self._normalize_tool_paths(tool_paths)

        # Get config file path for cache invalidation
        self.config_file_path = self._get_config_file_path()
        self._cache_namespace = self._build_cache_namespace()

        if self.use_cache:
            self._load_cache()
            # Check if config file changed and invalidate cache if needed
            self._check_config_staleness()
            # Check if tool code changed and invalidate cache if needed
            self._check_tool_staleness()
            # Check if previous run failed and invalidate cache
            self._check_previous_failure_staleness()

    def _normalize_tool_paths(
        self, tool_paths: Optional[Iterable[Path]]
    ) -> Tuple[Path, ...]:
        """Normalize tool paths to a tuple of resolved Path objects."""
        if not tool_paths:
            return ()
        normalized = []
        for item in tool_paths:
            try:
                path = Path(item).resolve()
                normalized.append(path)
            except Exception:
                continue
        return tuple(normalized)

    def _get_config_file_path(self) -> Optional[Path]:
        """
        Get the path to the development_tools_config.json file.

        Returns:
            Path to config file if found, None otherwise
        """
        try:
            # Try to get the config file path that was actually loaded
            import development_tools.config.config as config_module

            if (
                hasattr(config_module, "_config_file_path")
                and config_module._config_file_path
            ):
                return config_module._config_file_path
        except Exception:
            pass

        # Fallback: try to find it using the same logic as config loading
        try:
            config_file = (
                self.project_root
                / "development_tools"
                / "config"
                / "development_tools_config.json"
            )
            if not config_file.exists():
                config_file = self.project_root / "development_tools_config.json"
            if config_file.exists():
                return config_file
        except Exception:
            pass

        return None

    def _check_config_staleness(self) -> None:
        """
        Check if config file has changed since cache was created.
        If so, clear the cache to force regeneration with new config.
        """
        if not self.config_file_path or not self.config_file_path.exists():
            return

        try:
            # Get current config file mtime
            current_config_mtime = self.config_file_path.stat().st_mtime

            # Check cached config mtime
            cached_config_mtime = None
            if _CONFIG_MTIME_KEY in self.cache_data:
                cached_config_mtime = self.cache_data[_CONFIG_MTIME_KEY].get("mtime")

            # If config file is newer than cached mtime, clear cache
            if (
                cached_config_mtime is not None
                and current_config_mtime > cached_config_mtime
            ):
                if logger:
                    logger.info(
                        f"Config file changed (mtime: {current_config_mtime} > {cached_config_mtime}), "
                        f"invalidating cache for {self.tool_name or 'tool'}"
                    )
                self.clear_cache()
                # Update config mtime in cache immediately
                self._update_config_mtime_in_cache()
            elif cached_config_mtime is None:
                # No cached config mtime (first run or cache was cleared), store current mtime
                self._update_config_mtime_in_cache()
        except Exception as e:
            if logger:
                logger.debug(f"Error checking config file staleness: {e}")

    def _compute_config_signature(self) -> str:
        """
        Compute a stable signature for config file content.

        Falls back to file mtime when content hashing fails.
        """
        if not self.config_file_path or not self.config_file_path.exists():
            return "no_config"

        try:
            config_hash = hashlib.sha256(self.config_file_path.read_bytes()).hexdigest()
            return config_hash[:16]
        except Exception:
            try:
                return f"mtime:{self.config_file_path.stat().st_mtime}"
            except Exception:
                return "config_unavailable"

    def _build_cache_namespace(self) -> str:
        """Build namespace that scopes cache keys to tool/domain/config/tool-code inputs."""
        config_sig = self._compute_config_signature()
        tool_hash = self._compute_tool_hash() or "no_tool_hash"
        return f"{self.tool_name}|{self.domain}|cfg:{config_sig}|tool:{tool_hash[:16]}"

    def _update_config_mtime_in_cache(self) -> None:
        """Store current config file mtime in cache metadata."""
        if not self.config_file_path or not self.config_file_path.exists():
            return

        try:
            config_mtime = self.config_file_path.stat().st_mtime
            self.cache_data[_CONFIG_MTIME_KEY] = {
                "mtime": config_mtime,
                "results": {},  # Empty results, just storing mtime
            }
        except Exception:
            pass

    def _compute_tool_hash(self) -> Optional[str]:
        """Compute a hash for tool source files to detect code changes."""
        if not self.tool_paths:
            return None
        hasher = hashlib.sha256()
        has_data = False
        for path in self.tool_paths:
            try:
                if not path.exists() or not path.is_file():
                    continue
                hasher.update(path.read_bytes())
                has_data = True
            except Exception:
                return None
        return hasher.hexdigest() if has_data else None

    def _get_tool_mtimes(self) -> Dict[str, float]:
        """Return mtimes for tool source files for debug/traceability."""
        mtimes: Dict[str, float] = {}
        for path in self.tool_paths:
            try:
                if not path.exists():
                    continue
                key = str(path.relative_to(self.project_root)).replace("\\", "/")
                mtimes[key] = path.stat().st_mtime
            except Exception:
                continue
        return mtimes

    def _check_tool_staleness(self) -> None:
        """Check if tool code has changed since cache was created."""
        if not self.tool_paths:
            return
        try:
            current_hash = self._compute_tool_hash()
            if not current_hash:
                return

            cached_hash = None
            if _TOOL_HASH_KEY in self.cache_data:
                cached_hash = self.cache_data[_TOOL_HASH_KEY].get("hash")

            if cached_hash is not None and cached_hash != current_hash:
                if logger:
                    logger.info(
                        f"Tool code changed (hash mismatch), invalidating cache for {self.tool_name or 'tool'}"
                    )
                self.clear_cache()
                self._update_tool_metadata_in_cache(current_hash)
            elif cached_hash is None:
                self._update_tool_metadata_in_cache(current_hash)
        except Exception as e:
            if logger:
                logger.debug(f"Error checking tool code staleness: {e}")

    def _update_tool_metadata_in_cache(self, tool_hash: Optional[str] = None) -> None:
        """Store current tool code hash and mtimes in cache metadata."""
        if not tool_hash:
            tool_hash = self._compute_tool_hash()
        if tool_hash:
            self.cache_data[_TOOL_HASH_KEY] = {
                "hash": tool_hash,
                "results": {},
            }
        self.cache_data[_TOOL_MTIMES_KEY] = {
            "mtimes": self._get_tool_mtimes(),
            "results": {},
        }

    def _check_previous_failure_staleness(self) -> None:
        """Invalidate cache when previous run status indicates failure."""
        run_status = self.cache_data.get(_RUN_STATUS_KEY, {})
        if not isinstance(run_status, dict):
            return
        status = run_status.get("status")
        if status != "failed":
            return

        reason = run_status.get("error") or "previous run failed"
        if logger:
            logger.info(
                f"Previous cached run failed for {self.tool_name}; invalidating cache ({reason})"
            )
        self.clear_cache()
        self.mark_run_result(success=True)

    def mark_run_result(self, success: bool, error: Optional[str] = None) -> None:
        """Persist last run status for failure-aware invalidation."""
        self.cache_data[_RUN_STATUS_KEY] = {
            "status": "success" if success else "failed",
            "error": (error or "")[:500] if not success else "",
        }

    def _load_cache(self) -> None:
        """Load cache from disk if it exists."""
        if self.use_standardized_storage:
            # Use standardized storage
            try:
                from .output_storage import load_tool_cache

                loaded_data = load_tool_cache(
                    self.tool_name, self.domain, project_root=self.project_root
                )
                if loaded_data:
                    # load_tool_cache already extracts data from metadata wrapper, so loaded_data is the cache content
                    migrated_data = {}
                    for key, value in loaded_data.items():
                        if isinstance(value, dict) and (
                            "results" in value or key.startswith("__")
                        ):
                            migrated_data[key] = value
                    self.cache_data = migrated_data
                    if logger:
                        logger.debug(
                            f"Loaded cache from standardized storage ({self.tool_name}) with {len(self.cache_data)} entries"
                        )
                    return
            except Exception as e:
                if logger:
                    logger.warning(
                        f"Failed to load cache from standardized storage: {e}"
                    )
                # If standardized storage fails, start with empty cache
                # Tools will regenerate cache on next run
                self.cache_data = {}

    def save_cache(self) -> None:
        """Save cache to disk."""
        if not self.use_cache:
            return

        # Update config mtime in cache before saving
        self._update_config_mtime_in_cache()
        # Update tool hash in cache before saving
        self._update_tool_metadata_in_cache()
        # If run status has not been set explicitly, default to success on save.
        if _RUN_STATUS_KEY not in self.cache_data:
            self.mark_run_result(success=True)

        if self.use_standardized_storage:
            # Use standardized storage
            try:
                from .output_storage import save_tool_cache

                save_tool_cache(
                    self.tool_name,
                    self.domain,
                    self._sanitize_for_json(self.cache_data),
                    project_root=self.project_root,
                )
                if logger:
                    logger.debug(
                        f"Saved cache to standardized storage ({self.tool_name}) with {len(self.cache_data)} entries"
                    )
                return
            except Exception as e:
                if logger:
                    logger.warning(f"Failed to save cache to standardized storage: {e}")
                # If standardized storage fails, log warning but don't fall back to legacy
                # This ensures we fix standardized storage issues rather than silently using legacy paths

    def _get_file_cache_key(self, file_path: Path) -> str:
        """Generate cache key for a file (relative path from project root)."""
        try:
            rel_path = file_path.resolve().relative_to(self.project_root)
            rel_path_str = str(rel_path).replace("\\", "/")
        except ValueError:
            # File is outside project root, use absolute path
            rel_path_str = str(file_path.resolve())
        return f"{self._cache_namespace}|{rel_path_str}"

    def _is_file_cached(self, file_path: Path) -> bool:
        """Check if file results are cached and still valid (mtime matches)."""
        if not self.use_cache:
            return False

        cache_key = self._get_file_cache_key(file_path)
        if cache_key not in self.cache_data:
            return False

        cached_mtime = self.cache_data[cache_key].get("mtime")
        if cached_mtime is None:
            return False

        try:
            current_mtime = file_path.stat().st_mtime
            return current_mtime == cached_mtime
        except OSError:
            return False

    def get_cached(self, file_path: Path) -> Optional[T]:
        """
        Get cached results for a file if available and still valid.

        Args:
            file_path: Path to the file to check

        Returns:
            Cached results if available and valid, None otherwise
        """
        if not self._is_file_cached(file_path):
            return None

        cache_key = self._get_file_cache_key(file_path)
        cached_data = self.cache_data[cache_key].get("results")
        return cached_data

    def cache_results(self, file_path: Path, results: T) -> None:
        """
        Cache results for a file.

        Args:
            file_path: Path to the file being cached
            results: Results to cache (must be JSON-serializable)
        """
        if not self.use_cache:
            return

        try:
            cache_key = self._get_file_cache_key(file_path)
            mtime = file_path.stat().st_mtime
            self.cache_data[cache_key] = {"mtime": mtime, "results": results}
        except OSError:
            # File doesn't exist or can't be accessed, skip caching
            if logger:
                logger.warning(
                    f"Failed to cache results for {file_path} (file missing or inaccessible)"
                )
        except Exception as exc:
            if logger:
                logger.warning(f"Failed to cache results for {file_path}: {exc}")

    def clear_cache(self) -> None:
        """Clear all cached data (in memory only, call save_cache() to persist)."""
        self.cache_data = {}

    def get_cache_stats(self) -> Dict[str, Any]:
        """
        Get statistics about the cache.

        Returns:
            Dictionary with cache statistics (total_entries, tool_name, domain)
        """
        return {
            "total_entries": len(self.cache_data),
            "tool_name": self.tool_name,
            "domain": self.domain,
        }

    def _sanitize_for_json(self, value: Any) -> Any:
        """Convert non-serializable cache values into JSON-safe structures."""
        if isinstance(value, dict):
            return {k: self._sanitize_for_json(v) for k, v in value.items()}
        if isinstance(value, (list, tuple)):
            return [self._sanitize_for_json(v) for v in value]
        if isinstance(value, set):
            return [self._sanitize_for_json(v) for v in sorted(value)]
        if isinstance(value, Path):
            return value.as_posix()
        return value

"""
Audit orchestration methods for AIToolsService.

Contains methods for running audits in three tiers (quick, standard, full)
and managing audit state.
"""
# pyright: reportAttributeAccessIssue=false

import json
import os
import time
from datetime import datetime
from pathlib import Path
from typing import Any, Dict, List, Optional

from core.logger import get_component_logger

logger = get_component_logger("development_tools")

# Import output storage
from ..output_storage import save_tool_result, get_all_tool_results, load_tool_result
from ..file_rotation import create_output_file
from ..lock_state import cleanup_lock_paths, evaluate_lock_set, write_lock_metadata

# Module-level flag to track if ANY audit is in progress
_AUDIT_IN_PROGRESS_GLOBAL = False

# File-based lock for cross-process protection
_AUDIT_LOCK_FILE = None


class ToolExecutionError(RuntimeError):
    """Raised when a tool execution fails while preserving elapsed timing."""

    def __init__(self, tool_name: str, elapsed_time: float, original_exception: Exception):
        super().__init__(str(original_exception))
        self.tool_name = tool_name
        self.elapsed_time = elapsed_time
        self.original_exception = original_exception


def _get_status_file_mtimes(project_root: Path) -> Dict[str, float]:
    """Get modification times for all status files."""
    # Get status file paths from config
    try:
        from ... import config
        status_config = config.get_status_config()
        status_files_config = status_config.get('status_files', {})
        status_files = {
            'AI_STATUS.md': project_root / status_files_config.get('ai_status', 'development_tools/AI_STATUS.md'),
            'AI_PRIORITIES.md': project_root / status_files_config.get('ai_priorities', 'development_tools/AI_PRIORITIES.md'),
            'consolidated_report.md': project_root / status_files_config.get('consolidated_report', 'development_tools/consolidated_report.md')
        }
    except (ImportError, AttributeError, KeyError):
        status_files = {
            'AI_STATUS.md': project_root / 'development_tools' / 'AI_STATUS.md',
            'AI_PRIORITIES.md': project_root / 'development_tools' / 'AI_PRIORITIES.md',
            'consolidated_report.md': project_root / 'development_tools' / 'consolidated_report.md'
        }
    mtimes = {}
    for name, path in status_files.items():
        if path.exists():
            mtimes[name] = path.stat().st_mtime
        else:
            mtimes[name] = 0.0
    return mtimes


def _is_audit_in_progress(project_root: Path) -> bool:
    """Check if audit is in progress using in-memory flag + active metadata locks."""
    global _AUDIT_IN_PROGRESS_GLOBAL, _AUDIT_LOCK_FILE
    if _AUDIT_IN_PROGRESS_GLOBAL:
        return True

    try:
        from ... import config

        audit_lock_path = config.get_external_value(
            "paths.audit_lock_file", ".audit_in_progress.lock"
        )
        coverage_lock_path = config.get_external_value(
            "paths.coverage_lock_file", ".coverage_in_progress.lock"
        )
        audit_lock_file = project_root / Path(audit_lock_path)
        coverage_lock_file = project_root / Path(coverage_lock_path)
    except (ImportError, AttributeError):
        audit_lock_file = project_root / ".audit_in_progress.lock"
        coverage_lock_file = project_root / ".coverage_in_progress.lock"
    dev_tools_coverage_lock_file = (
        coverage_lock_file.parent / ".coverage_dev_tools_in_progress.lock"
    )
    lock_states = evaluate_lock_set(
        [audit_lock_file, coverage_lock_file, dev_tools_coverage_lock_file]
    )
    cleanup_targets = [
        entry["path"]
        for entry in (lock_states["stale"] + lock_states["malformed"])
        if isinstance(entry.get("path"), Path)
    ]
    if cleanup_targets:
        removed = cleanup_lock_paths(cleanup_targets)
        logger.warning(
            f"Removed {removed} stale/malformed audit lock file(s) during in-progress check"
        )
    return len(lock_states["active"]) > 0


class AuditOrchestrationMixin:
    """Mixin class providing audit orchestration methods to AIToolsService."""
    _CACHE_AWARE_TOOLS = {
        "run_test_coverage",
        "generate_dev_tools_coverage",
        "analyze_unused_imports",
        "analyze_legacy_references",
        "analyze_documentation_sync",
    }

    def run_analyze_duplicate_functions(self, *args, **kwargs):
        """Stub for mixin typing; implemented in ToolWrappersMixin."""
        raise NotImplementedError

    def _effective_tier3_state(self) -> str:
        """Return Tier 3 state including development-tools track impact."""
        outcome = (
            self.tier3_test_outcome
            if isinstance(getattr(self, "tier3_test_outcome", None), dict)
            else {}
        )
        state = outcome.get("state", "") or ""
        parallel = outcome.get("parallel", {}) if isinstance(outcome.get("parallel"), dict) else {}
        no_parallel = outcome.get("no_parallel", {}) if isinstance(outcome.get("no_parallel"), dict) else {}
        dev_tools = (
            outcome.get("development_tools", {})
            if isinstance(outcome.get("development_tools"), dict)
            else {}
        )

        def _track_label(track: Dict[str, Any]) -> str:
            classification = track.get("classification")
            if isinstance(classification, str) and classification.strip():
                return classification.strip()
            return "unknown"

        track_labels = (
            _track_label(parallel),
            _track_label(no_parallel),
            _track_label(dev_tools),
        )

        if state == "coverage_failed":
            return "coverage_failed"
        if "infra_cleanup_error" in track_labels:
            return "infra_cleanup_error"
        if "crashed" in track_labels:
            return "crashed"
        if "failed" in track_labels:
            return "test_failures"
        if any(label in {"passed", "skipped"} for label in track_labels):
            return "clean"
        if any(label == "unknown" for label in track_labels):
            return "coverage_failed"
        return "unknown"

    def _get_audit_lock_file_path(self) -> Path:
        """Get audit lock file path (configurable via config, defaults to .audit_in_progress.lock relative to project root)."""
        try:
            from ... import config
            # Default to generic path relative to project root (no development_tools/ assumption)
            lock_file_path = config.get_external_value('paths.audit_lock_file', '.audit_in_progress.lock')
            return self.project_root / lock_file_path
        except (ImportError, AttributeError):
            return self.project_root / 'development_tools' / '.audit_in_progress.lock'

    def _get_coverage_lock_file_path(self) -> Path:
        """Get coverage lock file path (configurable via config, defaults to .coverage_in_progress.lock relative to project root)."""
        try:
            from ... import config
            # Default to generic path relative to project root (no development_tools/ assumption)
            lock_file_path = config.get_external_value('paths.coverage_lock_file', '.coverage_in_progress.lock')
            return self.project_root / lock_file_path
        except (ImportError, AttributeError):
            return self.project_root / 'development_tools' / '.coverage_in_progress.lock'

    def run_audit(
        self,
        quick: bool = False,
        full: bool = False,
        include_overlap: bool = False,
        strict: bool = False,
    ):
        """Run audit workflow with three-tier structure."""
        global _AUDIT_IN_PROGRESS_GLOBAL, _AUDIT_LOCK_FILE

        lock_states = evaluate_lock_set(self._get_audit_related_lock_paths())
        cleanup_targets = [
            entry["path"]
            for entry in (lock_states["stale"] + lock_states["malformed"])
            if isinstance(entry.get("path"), Path)
        ]
        if cleanup_targets:
            removed = cleanup_lock_paths(cleanup_targets)
            logger.warning(
                f"Removed {removed} stale/malformed audit lock file(s) before starting audit"
            )
        if lock_states["active"]:
            lock_list = ", ".join(
                str(entry["path"])
                for entry in lock_states["active"]
                if isinstance(entry.get("path"), Path)
            )
            print(
                "Audit blocked: active audit/coverage lock file(s) present: "
                f"{lock_list}"
            )
            logger.error(
                "Audit blocked: active audit/coverage lock file(s) present: "
                f"{lock_list}"
            )
            return False

        # Determine audit tier
        if quick:
            tier = 1
            operation_name = "audit --quick (Tier 1)"
        elif full:
            tier = 3
            operation_name = "audit --full (Tier 3)"
        else:
            tier = 2
            operation_name = "audit (Tier 2 - standard)"

        # Print to console for user visibility (regardless of log level)
        print(f"Starting {operation_name}...")
        print("=" * 50)
        logger.info(f"Starting {operation_name}...")
        logger.info("=" * 50)

        self.current_audit_tier = tier
        self._audit_in_progress = True
        _AUDIT_IN_PROGRESS_GLOBAL = True
        # Track which tools were actually run in this audit tier
        self._tools_run_in_current_tier = set()
        # Track timing for each tool
        self._tool_timings = {}
        # Track execution status for each tool (success/failed)
        self._tool_execution_status = {}
        # Track cache metadata per tool for timing diagnostics
        self._tool_cache_metadata = {}
        self.tier3_test_outcome = {}
        self._internal_interrupt_detected = False
        # Track wall-clock runtime (accurate total audit duration with parallel execution)
        self._audit_wall_clock_start = time.perf_counter()

        # Create file-based lock
        if _AUDIT_LOCK_FILE is None:
            _AUDIT_LOCK_FILE = self._get_audit_lock_file_path()
        try:
            if not write_lock_metadata(_AUDIT_LOCK_FILE, lock_type="audit"):
                raise RuntimeError("write_lock_metadata returned False for audit lock")
        except Exception as e:
            logger.warning(f"Failed to create audit lock file: {e}")

        initial_mtimes = _get_status_file_mtimes(self.project_root)
        self._audit_start_mtimes = initial_mtimes

        self._include_overlap = include_overlap
        if full and not include_overlap:
            include_overlap = True
            self._include_overlap = True

        success = True
        try:
            # Tier 1: Quick audit tools
            print("Running Tier 1 tools (quick audit)...")
            logger.info("Running Tier 1 tools (quick audit)...")
            tier1_success = self._run_quick_audit_tools()
            if not tier1_success:
                success = False

            # Tier 2: Standard audit tools
            if tier >= 2:
                print("=" * 50)
                logger.info("=" * 50)
                print("Running Tier 2 tools (standard audit)...")
                logger.info("Running Tier 2 tools (standard audit)...")
                tier2_success = self._run_standard_audit_tools()
